-- referenceangle seed data
-- Source: SFHQ-T2I (Synthetic Faces HQ, text-to-image subset) via HF bitmind/SyntheticFacesHQ.
-- Synthetic faces (MIT-licensed, no subject/personality rights) -> freely redistributable.
-- Pose: MediaPipe FaceLandmarker transformation matrix -> stare head_pose_from_matrix (degrees).
-- Age/gender/emotion: DeepFace. Other booleans: blendshape + landmark heuristics.

DROP TABLE IF EXISTS reference;
CREATE TABLE reference (
  url text,
  pitch numeric, yaw numeric, roll numeric,
  gender text,
  lowage int, highage int,
  emotions text,
  issmiling boolean, sunglasses boolean, eyeglasses boolean,
  beard boolean, mustache boolean, eyesopen boolean, mouthopen boolean
);

